import React, {useState} from 'react';
// import logo from './logo.svg';
import './App.css';
import Register from './register';

const App = () => {
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isSubmitEnabled, setIsSubmitEnabled] = useState(false);

  const handlePasswordChange = (event) => {
    setPassword(event.target.value);
    setIsSubmitEnabled(event.target.value === confirmPassword);
  };

  const handleConfirmPasswordChange = (event) => {
    setConfirmPassword(event.target.value);
    setIsSubmitEnabled(event.target.value === password);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    // 处理表单提交逻辑
  };

  return (
    <div className="App">
      <nav class="menu">
        <ul class="subMenu">
          <li class="mainLink"><a href="https://www.vscinemas.com.tw/vsweb/#" class="firstMenu">影城介紹</a>
            <ul class="sublink">
              <li><a href="https://www.vscinemas.com.tw/vsweb/theater/index.aspx">威秀影城</a></li>
              <li><a href="https://www.vscinemas.com.tw/vsweb/theater/detail2.aspx?id=23">MUVIE</a></li>
            </ul>
          </li>
        </ul>
      </nav>

      <Register />
    </div>
  );
}

export default App;
